def get_headers(self) -> HTTPHeaderDict:
    headers = HTTPHeaderDict()  # Duplicate headers are legal
    # Check if Content-Type is explicitly set in headers
    content_type_explicitly_set = False
    if self.headers:
        if hasattr(self.headers, 'keys'):
            # Mapping (dict-like) headers
            content_type_explicitly_set = any(
                header.lower() == "content-type" for header in self.headers.keys()
            )
        else:
            # List of tuples headers
            content_type_explicitly_set = any(
                header[0].lower() == "content-type" for header in self.headers
            )

    # Only set content_type from self.content_type if not explicitly set in headers
    if self.content_type is not None and not content_type_explicitly_set:
        headers["Content-Type"] = self.content_type
    if self.headers:
        headers.extend(self.headers)
    return headers
